    def execute_where_query(self, collection_name, js_expression):
        collection = self.db[collection_name]
        query = {"$where": js_expression}
        results = list(collection.find(query))
        return results
    
    def execute_where_with_code(self, collection_name, js_code):
        collection = self.db[collection_name]
        code_obj = Code(js_code)
        query = {"$where": code_obj}
        results = list(collection.find(query))
        return results
    
    def filter_by_price_range(self, collection_name, min_price, max_price):
        js_expression = f"this.price >= {min_price} && this.price <= {max_price}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_stock_value(self, collection_name, min_value):
        js_expression = f"this.price * this.stock >= {min_value}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_custom_condition(self, collection_name, condition):
        return self.execute_where_query(collection_name, condition)
    
    def filter_with_complex_logic(self, collection_name, js_function):
        code = Code(js_function)
        return self.execute_where_with_code(collection_name, js_function)
    
    def filter_by_rating_and_stock(self, collection_name, min_rating, min_stock):
        js_expression = f"this.rating >= {min_rating} && this.stock >= {min_stock}"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_name_pattern(self, collection_name, pattern):
        js_expression = f"/{pattern}/i.test(this.name)"
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_by_calculated_field(self, collection_name, field1, field2, operator, threshold):
        js_expression = f"this.{field1} {operator} this.{field2} >= {threshold}"
        return self.execute_where_query(collection_name, js_expression)
    
    def advanced_filter_multi_condition(self, collection_name, conditions):
        js_parts = []
        for condition in conditions:
            js_parts.append(f"({condition})")
        js_expression = " && ".join(js_parts)
        return self.execute_where_query(collection_name, js_expression)
    
    def filter_with_user_function(self, collection_name, user_js_code):
        return self.execute_where_with_code(collection_name, user_js_code)
    
    def aggregate_with_where(self, collection_name, js_expression, group_by=None):
        collection = self.db[collection_name]
        pipeline = [
            {"$match": {"$where": js_expression}}
        ]
        
        if group_by:
            pipeline.append({
                "$group": {
                    "_id": f"${group_by}",
                    "count": {"$sum": 1},
                    "avg_price": {"$avg": "$price"},
                    "total_stock": {"$sum": "$stock"}
                }
            })
        
        results = list(collection.aggregate(pipeline))
        return results
    
    def filter_by_percentile(self, collection_name, field, percentile):
        js_code = f"""
        function() {{
            var threshold = {percentile};
            return this.{field} >= threshold;
        }}
        """
        return self.execute_where_with_code(collection_name, js_code)
    
    def filter_with_regex_and_math(self, collection_name, name_pattern, price_multiplier):
        js_expression = f"/{name_pattern}/i.test(this.name) && this.price * {price_multiplier} > 100"
        return self.execute_where_query(collection_name, js_expression)
    
    def custom_scoring_filter(self, collection_name, min_score):
        js_code = f"""
        function() {{
            var score = (this.rating * 0.5) + (this.stock / 10);
            return score >= {min_score};
        }}
        """
        return self.execute_where_with_code(collection_name, js_code)
    
    def print_results(self, results, title="Query Results"):
        print(f"\n{'='*60}")
        print(f"{title}")
        print(f"{'='*60}")
        if results:
            for idx, doc in enumerate(results, 1):
                doc_copy = doc.copy()
                doc_copy.pop('_id', None)
                print(f"{idx}. {json.dumps(doc_copy, indent=2)}")
            print(f"\nTotal results: {len(results)}")
        else:
            print("No results found")
        print(f"{'='*60}\n")


